projectConfigSchema:
{
  "type": "object",
  "title": "项目级共享配置",
  "description": "所有页面共享的配置项，运行时自动注入到每个页面的 props 中",
  "properties": {
    "brandName": {
      "type": "string",
      "title": "品牌名称",
      "default": "OpenCode Workbench",
      "description": "全局品牌名称，显示在所有页面顶部"
    },
    "primaryColor": {
      "type": "string",
      "format": "color",
      "title": "主题色",
      "default": "#6366f1",
      "description": "主色调，影响按钮、链接、高亮等元素的颜色"
    },
    "darkMode": {
      "type": "boolean",
      "title": "深色模式",
      "default": false,
      "description": "全局深色/浅色主题切换"
    },
    "companySlogan": {
      "type": "string",
      "title": "公司标语",
      "default": "用配置驱动一切",
      "description": "显示在页面底部的品牌标语"
    }
  }
}
